function computeCartTotalE(prices: number[], discount: number): number {
  let sum: number = 0;
  for (let i = 0; i < prices.length; i++) {
    sum += prices[i];
  }
  const rate: number = Math.min(1, Math.max(0, discount));
  return Math.round(sum * (1 - rate) * 100) / 100;
}

