function toggleSongInPlaylistE(songIds: number[], songId: number, add: boolean): number[] {
  const next: number[] = [];
  let found: boolean = false;
  for (let i = 0; i < songIds.length; i++) {
    if (songIds[i] === songId) {
      found = true;
      if (add) {
        next.push(songIds[i]);
      }
    } else {
      next.push(songIds[i]);
    }
  }
  if (add && !found) {
    next.push(songId);
  }
  return next;
}

