function decimalToBinaryE(value: number): string {
  let n: number = Math.abs(Math.floor(value));
  if (n === 0) {
    return '0';
  }
  let bits: string = '';
  while (n > 0) {
    bits = (n % 2) + bits;
    n = Math.floor(n / 2);
  }
  return value < 0 ? '-' + bits : bits;
}

