function reverseWordOrderE(sentence: string): string {
  const parts: string[] = sentence.trim().split(/\s+/);
  const out: string[] = [];
  for (let i = parts.length - 1; i >= 0; i--) {
    if (parts[i].length > 0) {
      out.push(parts[i]);
    }
  }
  return out.join(' ');
}
